param([string]$To="alex@1v1a.com")
$Sigs=@(@{File="sales_signature.htm";Name="Morgan Parker - Sales";Subj="Test 1/5 - sales@vectarr.com"},@{File="info_signature.htm";Name="Taylor Brooks - Info";Subj="Test 2/5 - info@vectarr.com"},@{File="support_signature.htm";Name="Casey Thompson - Support";Subj="Test 3/5 - support@vectarr.com"},@{File="accounts_signature.htm";Name="Jordan Mitchell - Accounts";Subj="Test 4/5 - accounts@vectarr.com"},@{File="admin_vectarr_signature.htm";Name="Anthony Ferrazza - Admin";Subj="Test 5/5 - admin@vectarr.com"})
$From="asferrazza@vectarr.com";$c=1
foreach($Sig in $Sigs){try{$s=Get-Content "$env:APPDATA\Microsoft\Signatures\$($Sig.File)"-Raw;$o=New-Object -ComObject Outlook.Application;$m=$o.CreateItem(0);$m.To=$To;$m.Subject=$Sig.Subj;$m.HTMLBody="<!DOCTYPE html><html><head><meta charset='UTF-8'></head><body style='font-family:Arial,sans-serif;'><p>Test $c/5 from Vectarr aliases with new phone +1 (650) 427-9450</p><br>$s</body></html>";$a=$o.Session.Accounts|Where-Object{$_.SmtpAddress-eq$From};if($a){$m.SendUsingAccount=$a};$m.Send();Write-Host "[$c/5] Sent: $($Sig.Name)";[System.Runtime.Interopservices.Marshal]::ReleaseComObject($m)|Out-Null;[System.Runtime.Interopservices.Marshal]::ReleaseComObject($o)|Out-Null;if($c-lt 5){Start-Sleep -Seconds 15}}catch{Write-Error "Failed: $_"}$c++}
Write-Host "All 5 test emails sent!"
